  @instantiable
  class HasMems() extends Module {
    @public val mem = Mem(8, UInt(32.W))
    @public val syncReadMem = SyncReadMem(8, UInt(32.W))
  }

  @instantiable
  class LeafInstantiable(val _bundle: Data) extends IsInstantiable {
    @public val bundle = _bundle
  }

  @instantiable
  class NestedInstantiable(val _in: LeafInstantiable, val _out: LeafInstantiable) extends IsInstantiable {
    @public val in = _in
    @public val out = _out
  }

  @instantiable
  class AddOneNestedInstantiableData(width: Int) extends Module {
    @public val in = IO(Input(UInt(width.W)))
    @public val out = IO(Output(UInt(width.W)))
    out := in + 1.U

    @public val leafOut = new LeafInstantiable(out)
    @public val leafIn = new LeafInstantiable(in)
    @public val nested = new NestedInstantiable(_in = leafIn, _out = leafOut)

  }
  @instantiable
  class HasUnsanitaryBundleField extends Module {
    class Interface extends Bundle {
      val `a-x` = UInt(8.W)
    }
    val realIn = IO(Input(new Interface))
    // It's important to have this redirection to trip an old bug
    @public val in = realIn.`a-x`
    @public val out = IO(Output(UInt(8.W)))
    out := in
  }

  @instantiable
  class HasAnalogWire extends RawModule {
    @public val port = IO(Analog(8.W))
    @public val wire = Wire(Analog(32.W))
    attach(port, wire)
  }

  class AddTwoNestedInstantiableData(width: Int) extends Module {
    val in = IO(Input(UInt(width.W)))
    val out = IO(Output(UInt(width.W)))
    val addOneDef = Definition(new AddOneNestedInstantiableData(width))
    val i0 = Instance(addOneDef)
    val i1 = Instance(addOneDef)
    i0.in := in
    i1.in := i0.out
    out := i1.out

    // both are equivalent to the above
    i1.leafIn.bundle := i0.leafOut.bundle
    i1.nested.in.bundle := i0.nested.out.bundle
  }

  class AddTwoNestedInstantiableDataSubmodule(addOneDef: Definition[AddOneNestedInstantiableData]) extends Module {
    val in = IO(Input(UInt(addOneDef.in.getWidth.W)))
    val out = IO(Output(UInt(addOneDef.out.getWidth.W)))
    val i0 = Instance(addOneDef)
    val i1 = Instance(addOneDef)
    i0.in := in
    i1.in := i0.out
    out := i1.out

    // both are equivalent to the above
    i1.leafIn.bundle := i0.leafOut.bundle
    i1.nested.in.bundle := i0.nested.out.bundle
  }

  class AddTwoNestedInstantiableDataWrapper(width: Int) extends Module {
    val in = IO(Input(UInt(width.W)))
    val out = IO(Output(UInt(width.W)))

    val original = Module(new AddOneNestedInstantiableData(width))
    val copy = Module(new AddTwoNestedInstantiableDataSubmodule(original.toDefinition))

    original.in := in
    copy.in := original.out
    out := copy.out

  }

  @instantiable
  class HasPublicUnit extends Module {
    @public val x: Unit = ()
    // Should also work in type-parameterized lookupable things
    @public val y: (Data, Unit) = (Wire(UInt(3.W)), ())
  }

  @instantiable
  class HasPublicActualDirection extends Module {
    val io = IO(new Bundle {
      val input = Input(UInt(8.W))
      val output = Output(UInt(8.W))
    })

    @public val inputDirection:  ActualDirection = DataMirror.directionOf(io.input)
    @public val outputDirection: ActualDirection = DataMirror.directionOf(io.output)
    @public val bundleDirection: ActualDirection = DataMirror.directionOf(io)
  }

  case class UserDefinedType(name: String, data: UInt, inst: Instance[AddOne])
  object UserDefinedType {
    implicit val lookupable: Lookupable.Simple[UserDefinedType] =
      Lookupable.product3[UserDefinedType, String, UInt, Instance[AddOne]](
        x => (x.name, x.data, x.inst),
        UserDefinedType.apply
      )
  }

  case class ParameterizedUserDefinedType[A, M <: BaseModule](value: A, inst: Instance[M])
  object ParameterizedUserDefinedType {
    implicit def lookupable[A: Lookupable, M <: BaseModule]: Lookupable.Simple[ParameterizedUserDefinedType[A, M]] =
      Lookupable.product2[ParameterizedUserDefinedType[A, M], A, Instance[M]](
        x => (x.value, x.inst),
        ParameterizedUserDefinedType.apply
      )
  }

  @instantiable
  class HasUserDefinedType extends Module {
    val defn = Definition(new AddOne)
    val inst0: Instance[AddOne] = Instance(defn)
    val inst1: Instance[AddOne] = Instance(defn)
    val wire = Wire(UInt(8.W))
    @public val simple = UserDefinedType("foo", wire, inst0)
    @public val parameterized = ParameterizedUserDefinedType(List(1, 2, 3), inst1)
  }

  class OpaqueRecord extends Record with OpaqueType {
    private val underlying = UInt(8.W)
    val elements = SeqMap("" -> underlying)
  }

  @instantiable
  class HasOpaqueType extends Module {
    @public val in = IO(Input(new OpaqueRecord))
    @public val out = IO(Output(new OpaqueRecord))
    @public val wire = Wire(new OpaqueRecord)
    wire := in
    out := wire
  }

  class OpaqueRecordBundle extends Bundle {
    val x = new OpaqueRecord
  }

  @instantiable
  class HasFlatIOWithOpaque extends RawModule {
    @public val io = FlatIO(new OpaqueRecordBundle)
  }

  // For test 9.c in DefinitionSpec - testing .toDefinition on Instance from imported Definition
  @instantiable
  class BarForImport extends RawModule {
    @public val a = WireInit(false.B)
  }
  @instantiable
  class FooForImport extends RawModule {
    @public val bar = Module(new BarForImport)
  }
}

